class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        n = len(s)
        best = 1
        for l in range(n):
            cnt = 0
            for r in range(l, n):
                if r > l and s[r] == s[r-1]:
                    cnt += 1
                    if cnt > 1:
                        break
                best = max(best, r - l + 1)
        return best
